// Предсобранный ESM payload untrusted overlay-bundle (логика 018 early-exit). Перехват в одной точке
// post_entry_management (`apply`): при подтверждённом неблагоприятном дрейфе для short (цена ВЫШЕ
// входа N баров) → patch idle→exit. Самодостаточен внутри module/ (FR-003); работает только с
// read-only snapshot 017 StrategyContext, регидрированным harness'ем.
export default function createOverlayModule() {
  return {
    apply(ctx) {
      const maxAdverseBars = Number(ctx.params.maxAdverseBars ?? 3);
      const position = ctx.position;
      if (position === null) return { kind: 'pass' };

      const history = ctx.data.closedCandles(maxAdverseBars);
      if (history.length < maxAdverseBars) return { kind: 'pass' };

      const adverse = history.every((bar) => bar.close > position.entryPrice);
      if (adverse) {
        return {
          kind: 'patch',
          patch: { kind: 'exit', target: 'overlay_early_exit', reason: 'early_exit_adverse_drift' },
        };
      }
      return { kind: 'annotate', notes: `held: ${maxAdverseBars}-bar adverse drift not confirmed` };
    },
  };
}
